50	struct LevelDbWrapper {
51	  leveldb::DB* ptr = nullptr;
52	  leveldb::WriteBatch batch;
53	
54	  leveldb::Status Open(const path& file_path, bool readonly) {
55	    leveldb::Options options;
56	    options.create_if_missing = !readonly;
57	    return leveldb::DB::Open(options, file_path.string(), &ptr);
58	  }
59	
60	  void Release() {
61	    delete ptr;
62	    ptr = nullptr;
63	  }
