65	  LevelDbCursor* CreateCursor() { return new LevelDbCursor(ptr); }
66	
67	  bool Fetch(const string& key, string* value) {
68	    auto status = ptr->Get(leveldb::ReadOptions(), key, value);
69	    return status.ok();
70	  }
