82	    if (write_batch) {
83	      batch.Delete(key);
84	      return true;
85	    }
86	    auto status = ptr->Delete(leveldb::WriteOptions(), key);
87	    return status.ok();
88	  }
89	
90	  void ClearBatch() { batch.Clear(); }
91	
92	  bool CommitBatch() {
93	    auto status = ptr->Write(leveldb::WriteOptions(), &batch);
94	    return status.ok();
95	  }
96	};
