17	
18	UserDbValue::UserDbValue(const string& value) {
19	  Unpack(value);
20	}
21	
22	string UserDbValue::Pack() const {
23	  std::ostringstream packed;
24	  packed << "c=" << commits << " d=" << dee << " t=" << tick;
25	  return packed.str();
26	}
27	
28	bool UserDbValue::Unpack(const string& value) {
29	  vector<string> kv;
30	  boost::split(kv, value, boost::is_any_of(" "));
31	  for (const string& k_eq_v : kv) {
32	    size_t eq = k_eq_v.find('=');
33	    if (eq == string::npos)
34	      continue;
35	    string k(k_eq_v.substr(0, eq));
36	    string v(k_eq_v.substr(eq + 1));
37	    try {
38	      if (k == "c") {
39	        commits = std::stoi(v);
40	      } else if (k == "d") {
41	        dee = (std::min)(10000.0, std::stod(v));
42	      } else if (k == "t") {
43	        tick = std::stoul(v);
44	      }
45	    } catch (...) {
46	      LOG(ERROR) << "failed in parsing key-value from userdb entry '" << k_eq_v
47	                 << "'.";
48	      return false;
49	    }
50	  }
51	  return true;
52	}
53	
54	static const string plain_userdb_extension(".userdb.txt");
55	
56	template <>
57	string UserDbComponent<TextDb>::extension() const {
58	  return plain_userdb_extension;
59	}
60	
61	string UserDb::snapshot_extension() {
62	  return plain_userdb_extension;
63	}
64	
65	// key ::= code <space> <Tab> phrase
66	
67	static bool userdb_entry_parser(const Tsv& row, string* key, string* value) {
68	  if (row.size() < 2 || row[0].empty() || row[1].empty()) {
69	    return false;
70	  }
71	  string code(row[0]);
72	  // fix invalid keys created by a buggy version
73	  if (code[code.length() - 1] != ' ')
74	    code += ' ';
75	  *key = code + "\t" + row[1];
76	  if (row.size() >= 3)
77	    *value = row[2];
78	  else
79	    value->clear();
80	  return true;
81	}
82	
83	static bool userdb_entry_formatter(const string& key,
84	                                   const string& value,
85	                                   Tsv* tsv) {
86	  Tsv& row(*tsv);
87	  boost::algorithm::split(row, key, boost::algorithm::is_any_of("\t"));
88	  if (row.size() != 2 || row[0].empty() || row[1].empty())
89	    return false;
90	  row.push_back(value);
91	  return true;
92	}
93	
94	static TextFormat plain_userdb_format = {
95	    userdb_entry_parser,
96	    userdb_entry_formatter,
97	    "Rime user dictionary",
98	};
99	
100	template <>
101	RIME_DLL UserDbWrapper<TextDb>::UserDbWrapper(const path& file_path,
102	                                              const string& db_name)
103	    : TextDb(file_path, db_name, "userdb", plain_userdb_format) {}
