110	bool UserDbHelper::IsUniformFormat(const path& file_path) {
111	  return boost::ends_with(file_path.filename().u8string(),
112	                          plain_userdb_extension);
113	}
114	
115	bool UserDbHelper::UniformBackup(const path& snapshot_file) {
116	  LOG(INFO) << "backing up userdb '" << db_->name() << "' to " << snapshot_file;
117	  TsvWriter writer(snapshot_file, plain_userdb_format.formatter);
118	  writer.file_description = plain_userdb_format.file_description;
119	  DbSource source(db_);
120	  try {
121	    writer << source;
122	  } catch (std::exception& ex) {
123	    LOG(ERROR) << ex.what();
124	    return false;
125	  }
126	  return true;
127	}
128	
129	bool UserDbHelper::UniformRestore(const path& snapshot_file) {
130	  LOG(INFO) << "restoring userdb '" << db_->name() << "' from "
131	            << snapshot_file;
132	  TsvReader reader(snapshot_file, plain_userdb_format.parser);
133	  DbSink sink(db_);
134	  try {
135	    reader >> sink;
136	  } catch (std::exception& ex) {
137	    LOG(ERROR) << ex.what();
138	    return false;
139	  }
140	  return true;
