27	struct DfsState {
28	  size_t depth_limit;
29	  size_t predict_word_from_depth;
30	  TickCount present_tick;
31	  Code code;
32	  vector<double> credibility;
33	  vector<double> quality_len;
34	  hash_map<int, DictEntryList> query_result;
35	  an<DbAccessor> accessor;
