41	  bool IsExactMatch(const string& prefix) {
42	    return boost::starts_with(key, prefix + '\t');
43	  }
44	  bool IsPrefixMatch(const string& prefix) {
45	    return boost::starts_with(key, prefix);
46	  }
47	  void RecruitEntry(size_t pos,
48	                    hash_map<string, SyllableId>* syllabary = nullptr);
49	  bool NextEntry() {
50	    if (!accessor->GetNextRecord(&key, &value)) {
51	      key.clear();
52	      value.clear();
53	      return false;  // reached the end
54	    }
55	    return true;
56	  }
57	  bool ForwardScan(const string& prefix) {
58	    if (!accessor->Jump(prefix)) {
59	      return false;
60	    }
61	    return NextEntry();
62	  }
63	  bool Backdate(const string& prefix) {
64	    DLOG(INFO) << "backdate; prefix: " << prefix;
65	    if (!accessor->Reset()) {
66	      LOG(WARNING) << "backdating failed for '" << prefix << "'.";
67	      return false;
68	    }
69	    return NextEntry();
70	  }
71	};
