73	void DfsState::RecruitEntry(size_t pos,
74	                            hash_map<string, SyllableId>* syllabary) {
75	  string full_code;
76	  auto e = UserDictionary::CreateDictEntry(
77	      key, value, present_tick, credibility.back(), quality_len.back(),
78	      syllabary ? &full_code : nullptr);
79	  if (e) {
80	    if (syllabary) {
81	      vector<string> syllables =
82	          strings::split(full_code, " ", strings::SplitBehavior::SkipToken);
83	      Code numeric_code;
84	      for (auto s = syllables.begin(); s != syllables.end(); ++s) {
85	        auto found = syllabary->find(*s);
86	        if (found == syllabary->end()) {
87	          LOG(ERROR) << "failed to recruit dict entry '" << e->text
88	                     << "', unrecognized syllable: " << *s;
89	          return;
90	        }
91	        numeric_code.push_back(found->second);
92	      }
93	      e->code = numeric_code;
94	      e->matching_code_size = code.size();
95	    } else {
96	      e->code = code;
97	    }
98	    DLOG(INFO) << "add entry at pos " << pos;
99	    query_result[pos].push_back(e);
100	  }
